// Filter out emails that already have AI results cached (classification !== null)
// Only pass through emails that need processing
const emails = $input.all();
const unprocessed = [];

for (const item of emails) {
  const email = item.json;
  // If classification is null/undefined, this email hasn't been processed yet
  if (!email.classification) {
    unprocessed.push({ json: email });
  }
}

// If no unprocessed emails, return empty to stop the workflow
if (unprocessed.length === 0) {
  return [{ json: { message: 'No new emails to process', count: 0 } }];
}

return unprocessed;

// Format a critical email alert for the user
const sentiment = $json;
const email = $('Filter Unprocessed').first().json;

const alert = {
  type: 'CRITICAL_EMAIL_ALERT',
  subject: email.subject || 'Unknown subject',
  sender: email.sender_email || email.sender || 'Unknown',
  sentiment: sentiment.sentiment || 'negative',
  intensity: sentiment.intensity || 0.8,
  reason: sentiment.alert_reason || 'Flagged as requiring human attention',
  message: `⚠️ CRITICAL EMAIL from ${email.sender || 'unknown sender'}\nSubject: ${email.subject}\nSentiment: ${sentiment.sentiment} (${Math.round((sentiment.intensity || 0.8) * 100)}% intensity)\nReason: ${sentiment.alert_reason || 'Requires personal response'}\n\nThis email has been flagged for your personal attention. Please review and respond manually.`
};

return [{ json: alert }];

// Quality gate: check if the AI draft passed the quality review
const data = $json;
const reviewScore = data.draft?.review_score || 0;
const approved = reviewScore >= 0.7;
const feedback = data.draft?.review_feedback || 'No review feedback';

const result = {
  ...data,
  quality_approved: approved,
  quality_score: reviewScore,
  quality_feedback: feedback
};

console.log(`Quality Review: score=${reviewScore}, approved=${approved}`);
return [{ json: result }];

// Format a daily digest message from analytics + todos
const analytics = $('Fetch Analytics').first().json;
const todoItems = $('Fetch Pending Todos').all();

const totalToday = analytics.total_today || 0;
const spamCount = analytics.spam_count || 0;
const pendingTasks = todoItems.length;

let digest = `📧 MailMind Daily Digest\n`;
digest += `========================\n`;
digest += `Emails processed today: ${totalToday}\n`;
digest += `Spam blocked: ${spamCount}\n`;
digest += `Pending tasks: ${pendingTasks}\n\n`;

if (pendingTasks > 0) {
  digest += `📋 Your Tasks:\n`;
  for (const item of todoItems.slice(0, 5)) {
    const todo = item.json;
    digest += `  • ${todo.title}`;
    if (todo.due_date) digest += ` (due: ${todo.due_date})`;
    digest += `\n`;
  }
  if (pendingTasks > 5) {
    digest += `  ... and ${pendingTasks - 5} more\n`;
  }
}

return [{ json: { digest, totalToday, spamCount, pendingTasks } }];
